// --- Sync Manager (higher-level orchestration) ---

class SyncManager {
  final ApiClient _apiClient;
  final List<SyncData> _pendingChanges = [];
  DateTime? _lastSyncedAt;
  Timer? _autoSyncTimer;
  bool _isSyncing = false;

  final StreamController<SyncStatus> _statusController =
      StreamController<SyncStatus>.broadcast();

  Stream<SyncStatus> get statusStream => _statusController.stream;

  SyncManager({required ApiClient apiClient}) : _apiClient = apiClient;

  void dispose() {
    _autoSyncTimer?.cancel();
    _statusController.close();
  }

  void addPendingChange(SyncData data) {
    _pendingChanges.add(data);
  }

  void startAutoSync({Duration interval = const Duration(minutes: 5)}) {
    _autoSyncTimer?.cancel();
    _autoSyncTimer = Timer.periodic(interval, (_) => sync());
  }

  void stopAutoSync() {
    _autoSyncTimer?.cancel();
    _autoSyncTimer = null;
  }

  Future<SyncResult?> sync() async {
    if (_isSyncing) return null;
    _isSyncing = true;
    _statusController.add(SyncStatus.syncing);

    try {
      final result = await _apiClient.syncData(
        localChanges: List.from(_pendingChanges),
        lastSyncedAt: _lastSyncedAt,
      );

      _pendingChanges.clear();
      _lastSyncedAt = result.syncedAt;
      _statusController.add(SyncStatus.completed);
      return result;
    } on NetworkException {
      _statusController.add(SyncStatus.offline);
      return null;
    } catch (e) {
      _statusController.add(SyncStatus.error);
      return null;
    } finally {
      _isSyncing = false;
    }
  }
}

enum SyncStatus {
  idle,
  syncing,
  completed,
  error,
  offline,
}

// --- Example usage / main entry point ---

Future<void> main() async {
  final apiClient = ApiClient();

  try {
    // 1. Login
    print('Logging in...');
    final token = await apiClient.login(
      email: 'user@example.com',
      password: 'securePassword123',
    );
    print('Logged in. Token expires at: ${token.expiresAt}');

    // 2. Fetch profile
    print('Fetching profile...');
    final profile = await apiClient.getProfile();
    print('Hello, ${profile.name} (${profile.email})');

    // 3. Update profile
    print('Updating profile...');
    final updatedProfile = await apiClient.updateProfile(name: 'New Name');
    print('Updated name to: ${updatedProfile.name}');

    // 4. Data synchronization
    print('Syncing data...');
    final syncManager = SyncManager(apiClient: apiClient);

    syncManager.statusStream.listen((status) {
      print('Sync status: $status');
    });

    // Add a local change
    syncManager.addPendingChange(SyncData(
      id: 'local-1',
      type: 'note',
      payload: {'title': 'My Note', 'content': 'Hello World'},
      updatedAt: DateTime.now(),
    ));

    // Perform sync
    final syncResult = await syncManager.sync();
    if (syncResult != null) {
      print('Sync complete: pulled ${syncResult.pulled.length} items, '
          'pushed ${syncResult.pushedCount} items');
    }

    // Start auto-sync every 5 minutes
    syncManager.startAutoSync();

    // 5. Pull incremental changes
    print('Pulling recent changes...');
    final recentChanges = await apiClient.pullChanges(
      since: DateTime.now().subtract(const Duration(hours: 24)),
      type: 'note',
    );
    print('Got ${recentChanges.length} recent note changes');

    // Cleanup
    syncManager.stopAutoSync();
    syncManager.dispose();

    // 6. Logout
    print('Logging out...');
    await apiClient.logout();
    print('Logged out.');
  } on ApiException catch (e) {
    print('API Error: $e');
  } on NetworkException catch (e) {
    print('Network Error: $e');
  } catch (e) {
    print('Unexpected error: $e');
  } finally {
    apiClient.dispose();
  }
}